+//     maxClientPageLimit, which is aligned to the store ceiling).
 //   - offset absent      → returns 0.
 //   - offset malformed   → HTTP 400 "invalid offset".
 //
@@ -64,7 +69,7 @@ func parsePageParams(c *fiber.Ctx) (int, int, error) {
 		if err != nil || n < 0 {
